function SpotifyEmbed() {
  const [url, setUrl] = React.useState('https://open.spotify.com/playlist/37i9dQZF1DXcBWIGoYBM5M');
  const [embedUrl, setEmbedUrl] = React.useState('https://open.spotify.com/embed/playlist/37i9dQZF1DXcBWIGoYBM5M');
  const update = () => {
    try {
      const u = new URL(url);
      const path = u.pathname.replace(/^\//, '');
      setEmbedUrl(`https://open.spotify.com/embed/${path}`);
    } catch {
      /* keep current */
    }
  };
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: '0 0 10px 0', fontSize: 16, color: '#222' }}>Spotify Embed</h3>
      <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
        <input value={url} onChange={(e) => setUrl(e.target.value)} placeholder="Spotify URL..." style={{ flex: 1, padding: '6px 10px', borderRadius: 8, border: '1px solid #ddd', fontFamily: 'inherit', fontSize: 13 }} />
        <button onClick={update} style={{ padding: '6px 12px', borderRadius: 8, border: 'none', background: '#1db954', color: '#fff', cursor: 'pointer', fontFamily: 'inherit', fontWeight: 500 }}>Load</button>
      </div>
      <div style={{ flex: 1, borderRadius: 10, overflow: 'hidden', border: '1px solid #eee' }}>
        <iframe src={embedUrl} width="100%" height="100%" style={{ border: 0 }} allow="encrypted-media"></iframe>
      </div>
    </div>
  );
}
render(<SpotifyEmbed/>);
